#!/usr/bin/env node
import assert from 'node:assert'
import fs from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)
const repoRoot = path.resolve(__dirname, '..', '..', '..')

function read(relativePath) {
    return fs.readFileSync(path.join(repoRoot, relativePath), 'utf8')
}

function assertContains(source, snippet, label) {
    assert.ok(source.includes(snippet), `${label} missing: ${snippet}`)
}

function assertNotContains(source, snippet, label) {
    assert.ok(!source.includes(snippet), `${label} still contains: ${snippet}`)
}

function assertMatches(source, pattern, label) {
    assert.ok(pattern.test(source), `${label} missing pattern: ${pattern}`)
}

