function testSuiteProductRouteContract() {
    const source = read('js/presentation/app-actions.js')
    assertContains(source, 'function isExplicitSuiteLegacyRegressionMode()', 'explicit suite regression mode guard')
    assertContains(source, "search.indexOf('test_env=1') !== -1", 'suite test_env regression flag')
    assertContains(source, "search.indexOf('suite_test=1') !== -1", 'suite_test regression flag')
    assertContains(source, "search.indexOf('ci=1') !== -1", 'ci regression flag')
    assertContains(source, 'function startVueReadingSuite(selection)', 'suite product Vue start helper')
    assertContains(source, "global.fetch(baseUrl + '/api/practice/reading-suite'", 'suite product API create call')
    assertContains(source, "api.openPracticeRoute('/reading-suite/' + encodeURIComponent(sessionId))", 'suite product Vue route call')
    assertContains(source, 'function startExplicitLegacySuiteRegression(selection)', 'explicit suite legacy regression helper')
    assertContains(source, 'return startExplicitLegacySuiteRegression(selection)', 'suite legacy path is gated')
    assertContains(source, 'return startVueReadingSuite(selection)', 'suite product path is Vue-only')
    assertNotContains(source, 'tryStartVueReadingSuite', 'suite product no try/fallback helper')
    assertNotContains(source, 'startedInVue', 'suite product no false-to-legacy fallback state')
    assertNotContains(source, 'return startLegacySuite(selection)', 'suite product no legacy fallback on Vue failure')
    assertNotContains(source, 'continueSuitePractice: continueSuitePractice', 'stale global continue suite export removed')
    assertNotContains(source, 'global.continueSuitePractice', 'stale global continue suite bridge removed')
}

